+import { normalizeOptions } from '../../src/plugin/normalize-options';
+
+let projectCount = 0;
+
+function createProjectRoot() {
+  projectCount += 1;
+  const projectRoot = `/virtual/metro-core-${projectCount}`;
+  vol.fromJSON({
+    [path.join(projectRoot, 'package.json')]: JSON.stringify({
+      dependencies: {
+        react: '19.1.0',
